import{_ as a,c as e,o as l,a4 as i}from"./chunks/framework.nQaBHiNx.js";const u=JSON.parse('{"title":"第六章 结构化开发方法","description":"","frontmatter":{"permalink":"/basic/ruankao/software-designer/06-structured-development-method.html"},"headers":[],"relativePath":"computer/ruankao/software-designer/06-第六章 结构化开发方法.md","filePath":"computer/ruankao/software-designer/06-第六章 结构化开发方法.md"}'),r={name:"computer/ruankao/software-designer/06-第六章 结构化开发方法.md"},o=i('<h1 id="第六章-结构化开发方法" tabindex="-1">第六章 结构化开发方法 <a class="header-anchor" href="#第六章-结构化开发方法" aria-label="Permalink to &quot;第六章 结构化开发方法&quot;">​</a></h1><p>结构化方法总的指导思想是自顶向下，逐层分解，他的基本原则是功能的分解与抽象。他是软件工程中最早出现的开发方法，特别适合于数据处理领域的问题，但是不适合解决大规模的特别复杂的项目，且难以适应需求的变化。</p><h2 id="_6-1-系统分析与设计概述" tabindex="-1">6.1 系统分析与设计概述 <a class="header-anchor" href="#_6-1-系统分析与设计概述" aria-label="Permalink to &quot;6.1 系统分析与设计概述&quot;">​</a></h2><h3 id="_6-1-1-系统分析概述" tabindex="-1">6.1.1 系统分析概述 <a class="header-anchor" href="#_6-1-1-系统分析概述" aria-label="Permalink to &quot;6.1.1 系统分析概述&quot;">​</a></h3><ol><li>系统分析的目的和任务</li><li>系统分析的主要步骤</li></ol><h3 id="_6-1-2-系统设计的基本原理" tabindex="-1">6.1.2 系统设计的基本原理 <a class="header-anchor" href="#_6-1-2-系统设计的基本原理" aria-label="Permalink to &quot;6.1.2 系统设计的基本原理&quot;">​</a></h3><ol><li>抽象</li><li>模块化</li><li>信息屏蔽（开闭原则）</li><li>模块独立（单一职责）</li></ol><h3 id="_6-1-3-系统总体结构设计" tabindex="-1">6.1.3 系统总体结构设计 <a class="header-anchor" href="#_6-1-3-系统总体结构设计" aria-label="Permalink to &quot;6.1.3 系统总体结构设计&quot;">​</a></h3><ol><li>系统结构设计原则</li><li>子系统划分</li><li>系统模块结构设计</li><li>数据存储设计</li></ol><h3 id="_6-1-4-系统文档" tabindex="-1">6.1.4 系统文档 <a class="header-anchor" href="#_6-1-4-系统文档" aria-label="Permalink to &quot;6.1.4 系统文档&quot;">​</a></h3><p>信息系统的文档是系统建设过程的“痕迹”，是系统维护人员的指南，是开发人员与用户交流的工具。规范的文档意味着系统是按照工程化开发的，意味着信息系统的质量有了形式上的保障。</p><h2 id="_6-2-结构化分析方法" tabindex="-1">6.2 结构化分析方法 <a class="header-anchor" href="#_6-2-结构化分析方法" aria-label="Permalink to &quot;6.2 结构化分析方法&quot;">​</a></h2><h3 id="_6-2-1-结构化分析方法概述" tabindex="-1">6.2.1 结构化分析方法概述 <a class="header-anchor" href="#_6-2-1-结构化分析方法概述" aria-label="Permalink to &quot;6.2.1 结构化分析方法概述&quot;">​</a></h3><p>抽象和分解是处理任何复杂问题的两个基本手段。</p><p>抽象是指忽略一个问题中与当前目标无关的那些方面，以便更充分地关注与当前目标有关的方面。</p><p>对于一个复杂的问题，人们很难一下子考虑问题的所有方面和全部细节，通常可以把一个大问题分解成若干个小问题，将每个小问题再分解成若干个更小的问题，每个最底层的问题都是足够简单、容易解决的，于是发展的问题也就因刃而解了。</p><h3 id="_6-2-2-数据流图" tabindex="-1">6.2.2 数据流图 <a class="header-anchor" href="#_6-2-2-数据流图" aria-label="Permalink to &quot;6.2.2 数据流图&quot;">​</a></h3><h3 id="_6-2-3-数据字典" tabindex="-1">6.2.3 数据字典 <a class="header-anchor" href="#_6-2-3-数据字典" aria-label="Permalink to &quot;6.2.3 数据字典&quot;">​</a></h3><h2 id="_6-3-结构化设计方法" tabindex="-1">6.3 结构化设计方法 <a class="header-anchor" href="#_6-3-结构化设计方法" aria-label="Permalink to &quot;6.3 结构化设计方法&quot;">​</a></h2><h3 id="_6-3-1-结构化设计的步骤" tabindex="-1">6.3.1 结构化设计的步骤 <a class="header-anchor" href="#_6-3-1-结构化设计的步骤" aria-label="Permalink to &quot;6.3.1 结构化设计的步骤&quot;">​</a></h3><h3 id="_6-3-2-数据流图到软件体系结构的映射" tabindex="-1">6.3.2 数据流图到软件体系结构的映射 <a class="header-anchor" href="#_6-3-2-数据流图到软件体系结构的映射" aria-label="Permalink to &quot;6.3.2 数据流图到软件体系结构的映射&quot;">​</a></h3><h2 id="_6-4-webapp-分析与设计" tabindex="-1">6.4 WebApp 分析与设计 <a class="header-anchor" href="#_6-4-webapp-分析与设计" aria-label="Permalink to &quot;6.4 WebApp 分析与设计&quot;">​</a></h2><h3 id="_6-4-1-webapp-的特性" tabindex="-1">6.4.1 WebApp 的特性 <a class="header-anchor" href="#_6-4-1-webapp-的特性" aria-label="Permalink to &quot;6.4.1 WebApp 的特性&quot;">​</a></h3><ol><li>网络密集性</li><li>并发性</li><li>无法预知的复杂量</li><li>性能</li><li>可用性</li><li>数据驱动</li></ol><h3 id="_6-4-2-webapp-需求模型" tabindex="-1">6.4.2 WebApp 需求模型 <a class="header-anchor" href="#_6-4-2-webapp-需求模型" aria-label="Permalink to &quot;6.4.2 WebApp 需求模型&quot;">​</a></h3><ol><li>内容模型</li><li>交互模型</li><li>功能模型</li><li>导航模型</li><li>配置模型</li></ol><h3 id="_6-4-3-webapp-设计" tabindex="-1">6.4.3 WebApp 设计 <a class="header-anchor" href="#_6-4-3-webapp-设计" aria-label="Permalink to &quot;6.4.3 WebApp 设计&quot;">​</a></h3><p>好的 WebApp 应该具有的最相关的通用特性是可用性、功能性、可靠性、效率、可维护性、安全性、可扩展性、以及及时性。</p><p>WebApp 的设计目标是简单性、一致性、符合性、健壮性、导航性、视觉吸引力与兼容性。</p><ol><li>架构设计</li><li>构件设计</li><li>内容设计</li><li>导航设计</li></ol><h2 id="_6-5-用户界面设计" tabindex="-1">6.5 用户界面设计 <a class="header-anchor" href="#_6-5-用户界面设计" aria-label="Permalink to &quot;6.5 用户界面设计&quot;">​</a></h2><h3 id="_6-5-1-用户界面设计的黄金原则" tabindex="-1">6.5.1 用户界面设计的黄金原则 <a class="header-anchor" href="#_6-5-1-用户界面设计的黄金原则" aria-label="Permalink to &quot;6.5.1 用户界面设计的黄金原则&quot;">​</a></h3><ol><li>用户操纵控制</li><li>减轻用户的记忆负担</li><li>保持界面一致</li></ol><h3 id="_6-5-2-用户界面的分析与设计" tabindex="-1">6.5.2 用户界面的分析与设计 <a class="header-anchor" href="#_6-5-2-用户界面的分析与设计" aria-label="Permalink to &quot;6.5.2 用户界面的分析与设计&quot;">​</a></h3><ol><li>用户界面分析和设计模型</li><li>用户界面分析和设计的过程</li></ol><h3 id="_6-5-3-用户界面设计问题" tabindex="-1">6.5.3 用户界面设计问题 <a class="header-anchor" href="#_6-5-3-用户界面设计问题" aria-label="Permalink to &quot;6.5.3 用户界面设计问题&quot;">​</a></h3><ol><li>系统响应事件</li><li>帮助设施</li><li>错误信息处理</li><li>菜单和命令标记</li></ol>',37),t=[o];function h(n,d,_,s,c,p){return l(),e("div",null,t)}const q=a(r,[["render",h]]);export{u as __pageData,q as default};
